/**
 * Priority Queue implementation for Dijkstra's algorithm.
 * Prioritizes: 1. Minimum time (T). 2. Maximum color (C) if times are equal.
 * Elements stored: [T, C, R, C]
 */
class PriorityQueue {
    constructor() {
        // Heap stores elements [T, C, R, C]
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    _compare(i, j) {
        const [T1, C1] = this.heap[i];
        const [T2, C2] = this.heap[j];

        // Primary comparison: Min Time (T)
        if (T1 !== T2) {
            return T1 < T2 ? -1 : 1;
        }
        // Secondary comparison: Max Color (C) -> Higher C is better, so it comes first (negative result)
        if (C1 !== C2) {
            return C1 > C2 ? -1 : 1;
        }
        // Tie breaker (shouldn't matter much for correctness but ensures stability)
        return 0;
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _heapifyUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = Math.floor((currentIndex - 1) / 2);
            if (this._compare(currentIndex, parentIndex) < 0) {
                this._swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    _heapifyDown(index) {
        let currentIndex = index;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let leftChild = 2 * currentIndex + 1;
            let rightChild = 2 * currentIndex + 2;
            let smallest = currentIndex;

            if (leftChild <= lastIndex && this._compare(leftChild, smallest) < 0) {
                smallest = leftChild;
            }
            if (rightChild <= lastIndex && this._compare(rightChild, smallest) < 0) {
                smallest = rightChild;
            }

            if (smallest !== currentIndex) {
                this._swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }

    enqueue(element) {
        this.heap.push(element);
        this._heapifyUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._heapifyDown(0);
        return root;
    }
}

/**
 * @param {number} n The number of rows.
 * @param {number} m The number of columns.
 * @param {number[][]} sources Array of [r, c, color] sources.
 * @return {number[][]} The final state of the grid.
 */
function solve(n, m, sources) {
    // Initialize grid to store final colors (0 means uncolored)
    const grid = Array(n).fill(0).map(() => Array(m).fill(0));

    // Initialize distance matrix: stores minimum time to reach (r, c)
    // Since max NM is 10^5, max time is also bounded by 10^5. Infinity works fine.
    const dist = Array(n).fill(0).map(() => Array(m).fill(Infinity));

    const pq = new PriorityQueue();

    // Directions: Up, Down, Left, Right
    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    // 1. Initialize sources
    for (const [r, c, color] of sources) {
        grid[r][c] = color;
        dist[r][c] = 0;
        // Push [Time, Color, R, C]
        pq.enqueue([0, color, r, c]);
    }

    // 2. Dijkstra's Algorithm
    while (!pq.isEmpty()) {
        const [t, c, r, c_coord] = pq.dequeue();

        // Check for stale entry based on time
        if (t > dist[r][c_coord]) {
            continue;
        }

        // Check for stale entry based on color at the minimum time
        // If we found an earlier path OR a path of equal time but higher color, this entry is suboptimal.
        // Since the PQ prioritizes max color for equal times, if the color we extract is less than what's recorded, we skip.
        if (t === dist[r][c_coord] && c < grid[r][c_coord]) {
             continue;
        }


        // 3. Propagate to neighbors
        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c_coord + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const t_new = t + 1;
                const c_new = c;

                // Case 1: Found a strictly faster path
                if (t_new < dist[nr][nc]) {
                    dist[nr][nc] = t_new;
                    grid[nr][nc] = c_new;
                    pq.enqueue([t_new, c_new, nr, nc]);
                } 
                // Case 2: Found a path of equal minimum time, but with a better (larger) color
                else if (t_new === dist[nr][nc] && c_new > grid[nr][nc]) {
                    grid[nr][nc] = c_new;
                    // Re-enqueueing with a better color at the same time ensures this path is processed correctly 
                    // and influences subsequent steps if needed, although the time constraint prevents infinite looping.
                    pq.enqueue([t_new, c_new, nr, nc]);
                }
            }
        }
    }

    return grid;
}
